-- Ken's Hardened V2 Fix

local b64_0xllllll = {}
local char_0xI1llll='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0x11ll1I=1,#char_0xI1llll do b64_0xllllll[char_0xI1llll:sub(i_0x11ll1I,i_0x11ll1I)] = i_0x11ll1I - 1 end

function b64_0xllllll.dec_0xlIIllI(d_0xlIlllI)
    d_0xlIlllI = string.gsub(d_0xlIlllI, '[^'..char_0xI1llll..'=]', '')
    local r_0xIlI111 = {}
    for i_0x11ll1I=1, #d_0xlIlllI, 4 do
        local c_0xl11lIl = b64_0xllllll[d_0xlIlllI:sub(i_0x11ll1I,i_0x11ll1I)] or 0
        local c_0xlII1lI = b64_0xllllll[d_0xlIlllI:sub(i_0x11ll1I+1,i_0x11ll1I+1)] or 0
        local c_0xlI1I11, c_0xl1lIll = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xlIlllI:sub(i_0x11ll1I+2,i_0x11ll1I+2)
        if ch3 == "=" then has3 = false else c_0xlI1I11 = b64_0xllllll[ch3] or 0 end
        local ch4 = d_0xlIlllI:sub(i_0x11ll1I+3,i_0x11ll1I+3)
        if ch4 == "=" then has4 = false else c_0xl1lIll = b64_0xllllll[ch4] or 0 end
        local b_0x1lll1l = c_0xl11lIl * (2^18) + c_0xlII1lI * (2^12) + c_0xlI1I11 * (2^6) + c_0xl1lIll
        local b_0xIlIllI = math.floor(b_0x1lll1l / (2^16)) % (2^8)
        local b_0xIIll11 = math.floor(b_0x1lll1l / (2^8)) % (2^8)
        local b_0xllllII = b_0x1lll1l % (2^8)
        table.insert(r_0xIlI111, string.char(b_0xIlIllI))
        if has3 then table.insert(r_0xIlI111, string.char(b_0xIIll11)) end
        if has4 then table.insert(r_0xIlI111, string.char(b_0xllllII)) end
    end
    return table.concat(r_0xIlI111)
end


local function bxor_0xIl1lII(a_0xllIl1l,b_0xlIlIlI)
    if bit32 then return bit32.bxor(a_0xllIl1l,b_0xlIlIlI) end
    local r_0x1I1IlI = 0
    for i_0xll1lII = 0, 7 do
        local x_0xlIllII = a_0xllIl1l % 2
        local y_0xI11IIl = b_0xlIlIlI % 2
        if x_0xlIllII ~= y_0xI11IIl then r_0x1I1IlI = r_0x1I1IlI + (2^i_0xll1lII) end
        a_0xllIl1l = math.floor(a_0xllIl1l / 2)
        b_0xlIlIlI = math.floor(b_0xlIlIlI / 2)
    end
    return r_0x1I1IlI
end


local function bxor_str_0xII1Ill(s_0xIllIl1, k_0xllIlll)
    local r_0xllIII1 = {}
    for i_0xlIIIIl=1, #s_0xIllIl1 do
        local b_0xIl1Il1 = string.byte(s_0xIllIl1, i_0xlIIIIl)
        local kb_0xllIIIl = string.byte(k_0xllIlll, (i_0xlIIIIl-1) % #k_0xllIlll + 1)
        r_0xllIII1[i_0xlIIIIl] = string.char(bxor_0xIl1lII(b_0xIl1Il1, kb_0xllIIIl))
    end
    return table.concat(r_0xllIII1)
end


local function getkeys_0xII1lI1()
    local seed = b64_0xllllll.dec_0xlIIllI("NWJwU2NPcWM=")
    local k1_enc = b64_0xllllll.dec_0xlIIllI("TzICJwIZGDk=")
    local k2_enc = b64_0xllllll.dec_0xlIIllI("ZjcFNzR7KQ0=")
    return bxor_str_0xII1Ill(k1_enc, seed), bxor_str_0xII1Ill(k2_enc, seed)
end


local function cff_0xll111l(a_0xlllIII)
    local st_0x1IIllI = 0
    local res_0xlI11I1 = a_0xlllIII
    while true do
        if st_0x1IIllI == 0 then
            res_0xlI11I1 = res_0xlI11I1 + 1
            st_0x1IIllI = 1
        elseif st_0x1IIllI == 1 then
            res_0xlI11I1 = res_0xlI11I1 * 2
            st_0x1IIllI = 2
        elseif st_0x1IIllI == 2 then
            res_0xlI11I1 = res_0xlI11I1 - 3
            st_0x1IIllI = 3
        else
            break
        end
    end
    return res_0xlI11I1
end


local function chain_0xlIII1I(x) return x*2 end
local function chain_0xI1Il11(x) return chain_0xlIII1I(x)+1 end


local d_0xI1IllI = {
  {op=255, val="", is_enc=true},
}
local pc_0x1IIIll = 1
local stk_0xl11lll = {}
stk_0xl11lll._jmp = nil


local disp_0xllIlll = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xII1lI1()

local state_0xlIllll = 0
while true do
    if state_0xlIllll == 0 then  -- FETCH
        if pc_0x1IIIll > #d_0xI1IllI then break end
        local inst = d_0xI1IllI[pc_0x1IIIll]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xllllll.dec_0xlIIllI(val)
            d = bxor_str_0xII1Ill(d, k2)
            val = bxor_str_0xII1Ill(d, k1)
        end
        stk_0xl11lll._jmp = nil
        pc_0x1IIIll = pc_0x1IIIll + 1
        cur_op_0xlII1ll = opcode
        cur_val_0xlIIIII = val
        state_0xlIllll = 1

    elseif state_0xlIllll == 1 then  -- EXECUTE
        local handler = disp_0xllIlll[cur_op_0xlII1ll]
        if handler then
            handler(stk_0xl11lll, cur_val_0xlIIIII)
        end
        if stk_0xl11lll._jmp then
            pc_0x1IIIll = pc_0x1IIIll + stk_0xl11lll._jmp
        end
        state_0xlIllll = 0
    else
        break
    end
end
